import { NextResponse } from "next/server";
import fs from "fs/promises";
import path from "path";
import { createCanvas } from "canvas";
import Tesseract from "tesseract.js";
import * as pdfjsLib from "pdfjs-dist";

// Set worker path for PDF.js
pdfjsLib.GlobalWorkerOptions.workerSrc = path.join(
  process.cwd(),
  "node_modules/pdfjs-dist/build/pdf.worker.min.js"
);

// Upload directory
const uploadDir = path.join(process.cwd(), "public/uploads");

export async function POST(req: Request) {
  try {
    // Parse FormData
    const formData = await req.formData();
    const file = formData.get("file") as File;
    if (!file)
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });

    // Save file
    const filePath = path.join(uploadDir, file.name);
    const buffer = Buffer.from(await file.arrayBuffer());
    await fs.writeFile(filePath, buffer);

    console.log("PDF saved at:", filePath);

    // Extract text from PDF
    const extractedText = await extractTextFromPDF(filePath);

    return NextResponse.json({ text: extractedText });
  } catch (error) {
    console.error("OCR Extraction Error:", error);
    return NextResponse.json(
      { error: "OCR Extraction Failed" },
      { status: 500 }
    );
  }
}

// Function to extract text from a PDF
async function extractTextFromPDF(pdfPath: string): Promise<string> {
  try {
    const data = await fs.readFile(pdfPath);
   const loadingTask = pdfjsLib.getDocument({ data: new Uint8Array(data) });
   const pdf = await loadingTask.promise;


    console.log("PDF Loaded Successfully:", pdf.numPages, "pages found");

    let fullText = "";

    for (let pageNum = 1; pageNum <= pdf.numPages; pageNum++) {
      console.log(`Processing page ${pageNum}...`);
      const page = await pdf.getPage(pageNum);
      const viewport = page.getViewport({ scale: 2 });

      // Convert PDF page to image
      const canvas = createCanvas(viewport.width, viewport.height);
      const ctx = canvas.getContext("2d");

      await page.render({ canvasContext: ctx, viewport }).promise;

      // Save the image for debugging
      const imagePath = path.join(uploadDir, `page-${pageNum}.png`);
      await fs.writeFile(imagePath, canvas.toBuffer("image/png"));
      console.log(`Saved page ${pageNum} image at:`, imagePath);

      // Run OCR on the image
      const {
        data: { text },
      } = await Tesseract.recognize(imagePath, "eng");

      console.log(`Extracted text from page ${pageNum}:`, text);
      fullText += text + "\n";
    }

    return fullText;
  } catch (error) {
    console.error("Error extracting text from PDF:", error);
    throw new Error("PDF processing failed");
  }
}
